import React, { useState, useEffect, useMemo } from 'react';
import { Task, Member, Project, Group } from '../types';

interface TaskFormModalProps {
  task?: Task | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: Partial<Task>) => void;
  members: Member[];
  groups: Group[];
  projects: Project[];
  currentProjectId?: string;
}

export const TaskFormModal: React.FC<TaskFormModalProps> = ({ 
  task, 
  isOpen, 
  onClose, 
  onSave, 
  members,
  groups,
  projects,
  currentProjectId
}) => {
  const [formData, setFormData] = useState<Partial<Task>>({
    title: '',
    outcome: '',
    projectId: '',
    assigneeIds: [],
    managerIds: [],
    startDate: new Date().toISOString().split('T')[0],
    dueDate: new Date().toISOString().split('T')[0],
    progress: 0,
    logs: [],
    executionTasks: []
  });

  const selectedProject = useMemo(() => {
    return projects.find(p => p.id === formData.projectId) || null;
  }, [formData.projectId, projects]);

  useEffect(() => {
    if (selectedProject) {
      setFormData(prev => {
        let newStart = prev.startDate || '';
        let newDue = prev.dueDate || '';

        if (newStart < selectedProject.startDate) newStart = selectedProject.startDate;
        if (selectedProject.endDate && newStart > selectedProject.endDate) newStart = selectedProject.endDate;

        if (newDue < newStart) newDue = newStart;
        if (selectedProject.endDate && newDue > selectedProject.endDate) newDue = selectedProject.endDate;

        return { ...prev, startDate: newStart, dueDate: newDue };
      });
    }
  }, [formData.projectId, selectedProject]);

  const availableMembersByGroup = useMemo(() => {
    const memberPool = (selectedProject && selectedProject.memberIds && selectedProject.memberIds.length > 0)
      ? members.filter(m => selectedProject.memberIds.includes(m.id))
      : [];

    const map: Record<string, Member[]> = {};
    groups.forEach(g => map[g.id] = []);
    map['unassigned'] = [];

    memberPool.forEach(m => {
      if (m.groupId && map[m.groupId]) {
        map[m.groupId].push(m);
      } else {
        map['unassigned'].push(m);
      }
    });
    return map;
  }, [selectedProject, members, groups]);

  useEffect(() => {
    if (task) {
      setFormData({ 
        ...task, 
        assigneeIds: task.assigneeIds || [],
        managerIds: task.managerIds || []
      });
    } else if (isOpen) {
      let defaultProject = (currentProjectId && currentProjectId !== 'all') ? currentProjectId : (projects[0]?.id || 'default_project');
      const proj = projects.find(p => p.id === defaultProject);

      setFormData({
        id: Date.now().toString(),
        title: '',
        outcome: '',
        projectId: defaultProject,
        assigneeIds: [],
        managerIds: [],
        startDate: proj?.startDate || new Date().toISOString().split('T')[0],
        dueDate: proj?.endDate || proj?.startDate || new Date().toISOString().split('T')[0],
        progress: 0,
        logs: [],
        executionTasks: []
      });
    }
  }, [task, isOpen, projects, currentProjectId]);

  if (!isOpen) return null;

  const toggleAssignee = (id: string) => {
    const current = formData.assigneeIds || [];
    if (current.includes(id)) {
      setFormData({ ...formData, assigneeIds: current.filter(x => x !== id) });
    } else {
      setFormData({ ...formData, assigneeIds: [...current, id] });
    }
  };

  const toggleManager = (id: string) => {
    const current = formData.managerIds || [];
    if (current.includes(id)) {
      setFormData({ ...formData, managerIds: current.filter(x => x !== id) });
    } else {
      setFormData({ ...formData, managerIds: [...current, id] });
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.managerIds || formData.managerIds.length === 0) {
      alert('请至少指派一名作战指挥官（负责人）');
      return;
    }

    if (formData.startDate && formData.dueDate && formData.startDate > formData.dueDate) {
      alert('节点启动日期不能晚于交付日期');
      return;
    }

    if (selectedProject) {
      if (formData.startDate && formData.startDate < selectedProject.startDate) {
        alert(`节点时间非法：不能早于项目启动时间 (${selectedProject.startDate})`);
        return;
      }
      if (selectedProject.endDate && formData.dueDate && formData.dueDate > selectedProject.endDate) {
        alert(`节点时间非法：不能晚于项目交付时间 (${selectedProject.endDate})`);
        return;
      }
    }

    onSave(formData);
    onClose();
  };

  const hasAnyMembers = (Object.values(availableMembersByGroup) as Member[][]).some(arr => arr.length > 0);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-xl p-6 m-4 animate-[fadeIn_0.2s_ease-out] overflow-y-auto max-h-[90vh] scrollbar-hide">
        <h2 className="text-xl font-bold text-slate-800 mb-6 border-l-4 border-warning pl-4">{task ? '编辑作战节点' : '定义核心作战节点'}</h2>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-xs font-black text-slate-400 mb-1.5 uppercase tracking-widest">节点名称</label>
            <input 
              type="text" 
              value={formData.title} 
              onChange={e => setFormData({...formData, title: e.target.value})}
              placeholder="例如：核心数据库迁移..."
              className="w-full px-4 py-2.5 border border-slate-300 rounded-xl focus:ring-2 focus:ring-warning outline-none font-bold text-slate-700 shadow-sm"
              required
            />
          </div>

          <div>
            <label className="block text-xs font-black text-slate-400 mb-1.5 uppercase tracking-widest">交付目标愿景</label>
            <textarea 
              value={formData.outcome} 
              onChange={e => setFormData({...formData, outcome: e.target.value})}
              placeholder="请描述该节点的具体交付物或预期达成效果..."
              className="w-full px-4 py-2.5 border border-slate-300 rounded-xl focus:ring-2 focus:ring-warning outline-none font-bold text-slate-700 h-24 resize-none shadow-sm"
              required
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-black text-slate-400 mb-1.5 uppercase tracking-widest">所属立项项目</label>
              <select 
                value={formData.projectId} 
                onChange={e => setFormData({...formData, projectId: e.target.value, assigneeIds: [], managerIds: []})}
                className="w-full px-4 py-2.5 border border-slate-300 rounded-xl focus:ring-2 focus:ring-warning outline-none bg-white font-bold text-slate-700 shadow-sm"
                required
              >
                {projects.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
             <div className="flex flex-col justify-center">
              {selectedProject && (
                <div className="flex items-center gap-2 px-3 py-2 bg-slate-50 rounded-xl border border-slate-100">
                    <div className="w-1.5 h-1.5 rounded-full bg-warning animate-pulse"></div>
                    <span className="text-[9px] text-slate-500 font-bold uppercase tracking-widest leading-none">
                      项目窗口: <span className="text-warning">{selectedProject.startDate}</span> ~ <span className="text-warning">{selectedProject.endDate || '无'}</span>
                    </span>
                </div>
              )}
            </div>
          </div>

          {/* 管理负责人选择：金黄色高亮，代表核心管理权 */}
          <div>
            <label className="flex items-center justify-between mb-2">
               <span className="text-xs font-black text-warning uppercase tracking-widest">作战节点指挥官 (管理负责人)</span>
               <span className="text-[8px] font-black text-slate-400 uppercase">拥有日志查看与最高管理权</span>
            </label>
            <div className="border-2 border-warning/20 rounded-xl p-4 bg-warning/5 max-h-40 overflow-y-auto space-y-4 scrollbar-hide">
               {hasAnyMembers ? (
                 <>
                   {groups.map(group => {
                     const groupMembers = availableMembersByGroup[group.id] || [];
                     if (groupMembers.length === 0) return null;
                     return (
                       <div key={`mgr-${group.id}`}>
                          <div className="text-[9px] font-black text-warning/60 uppercase tracking-widest mb-1.5 px-1">{group.name}</div>
                          <div className="grid grid-cols-2 gap-2">
                             {groupMembers.map(m => (
                               <div 
                                 key={`mgr-${m.id}`} 
                                 onClick={() => toggleManager(m.id)}
                                 className={`flex items-center gap-2 p-1.5 rounded-lg cursor-pointer border-2 transition-all ${
                                   formData.managerIds?.includes(m.id) 
                                   ? 'bg-warning border-warning shadow-lg text-slate-900 scale-[1.02]' 
                                   : 'bg-white border-slate-100 hover:border-warning/30 text-slate-400'
                                 }`}
                               >
                                  <img src={m.avatar} className={`w-5 h-5 rounded-full border ${formData.managerIds?.includes(m.id) ? 'border-white' : 'border-slate-100'}`} />
                                  <span className="text-[10px] font-black truncate">{m.name}</span>
                               </div>
                             ))}
                          </div>
                       </div>
                     );
                   })}
                 </>
               ) : (
                 <p className="text-center py-4 text-[10px] text-slate-400 italic font-black uppercase tracking-widest">请先在立项管理中分配项目成员</p>
               )}
            </div>
          </div>

          <div>
            <label className="block text-xs font-black text-slate-400 mb-2 uppercase tracking-widest">执行团队成员</label>
            <div className="border border-slate-200 rounded-xl p-4 bg-slate-50/50 max-h-40 overflow-y-auto space-y-4 scrollbar-hide">
               {hasAnyMembers ? (
                 <>
                   {groups.map(group => {
                     const groupMembers = availableMembersByGroup[group.id] || [];
                     if (groupMembers.length === 0) return null;
                     return (
                       <div key={`assign-${group.id}`}>
                          <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1.5 px-1">{group.name}</div>
                          <div className="grid grid-cols-2 gap-2">
                             {groupMembers.map(m => (
                               <div 
                                 key={`assign-${m.id}`} 
                                 onClick={() => toggleAssignee(m.id)}
                                 className={`flex items-center gap-2 p-1.5 rounded-lg cursor-pointer border transition-all ${
                                   formData.assigneeIds?.includes(m.id) 
                                   ? 'bg-slate-900 border-slate-900 shadow-md text-white' 
                                   : 'bg-white border-slate-100 hover:border-slate-300 text-slate-400'
                                 }`}
                               >
                                  <img src={m.avatar} className="w-5 h-5 rounded-full" />
                                  <span className="text-[10px] font-black truncate">{m.name}</span>
                               </div>
                             ))}
                          </div>
                       </div>
                     );
                   })}
                 </>
               ) : (
                 <p className="text-center py-4 text-[10px] text-slate-400 italic font-black uppercase tracking-widest">请先在立项管理中分配项目成员</p>
               )}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-black text-slate-400 mb-1.5 uppercase tracking-widest">节点启动</label>
              <input 
                type="date" 
                value={formData.startDate} 
                min={selectedProject?.startDate}
                max={selectedProject?.endDate || undefined}
                onChange={e => setFormData({...formData, startDate: e.target.value})} 
                className="w-full px-4 py-2 border border-slate-300 rounded-xl outline-none font-bold text-slate-700 focus:ring-2 focus:ring-warning shadow-sm" 
                required 
              />
            </div>
            <div>
              <label className="block text-xs font-black text-slate-400 mb-1.5 uppercase tracking-widest">最终交付</label>
              <input 
                type="date" 
                value={formData.dueDate} 
                min={formData.startDate || selectedProject?.startDate}
                max={selectedProject?.endDate || undefined}
                onChange={e => setFormData({...formData, dueDate: e.target.value})} 
                className="w-full px-4 py-2 border border-slate-300 rounded-xl outline-none font-bold text-slate-700 focus:ring-2 focus:ring-warning shadow-sm" 
                required 
              />
            </div>
          </div>

          <div className="flex space-x-3 mt-4 pt-4 border-t border-slate-100">
            <button type="button" onClick={onClose} className="flex-1 px-4 py-3 border border-slate-300 text-slate-500 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition-all">取消</button>
            <button type="submit" className="flex-1 px-4 py-3 bg-slate-900 text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-black shadow-2xl transition-all">确认部署节点</button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React from 'react';
import { Task, Member, TaskStatus } from '../types';
import { ProgressBar } from './ProgressBar';

interface TaskCardProps {
  task: Task;
  allMembers: Member[];
  projectName?: string;
  onUpdateClick: (task: Task) => void;
  onEditTask: (task: Task) => void;
  onDeleteTask: (taskId: string) => void;
  onDetailClick: (task: Task) => void;
  isActive?: boolean;
}

export const TaskCard: React.FC<TaskCardProps> = ({ 
  task, 
  allMembers, 
  projectName,
  onUpdateClick,
  onEditTask,
  onDeleteTask,
  onDetailClick,
  isActive = false
}) => {
  const today = new Date();
  const dueDate = new Date(task.dueDate);
  const daysLeft = Math.ceil((dueDate.getTime() - today.getTime()) / (1000 * 3600 * 24));

  let computedStatus: 'normal' | 'risk' | 'delayed' | 'completed' = 'normal';
  let statusLabel = TaskStatus.ON_TRACK;

  if (task.progress === 100) {
    computedStatus = 'completed';
    statusLabel = TaskStatus.COMPLETED;
  } else if (daysLeft < 0) {
    computedStatus = 'delayed';
    statusLabel = TaskStatus.DELAYED;
  } else if (daysLeft <= 3 && task.progress < 80) {
    computedStatus = 'risk';
    statusLabel = TaskStatus.AT_RISK;
  }

  const executionTasksTotal = task.executionTasks?.length || 0;
  const executionTasksCompleted = task.executionTasks?.filter(m => m.isCompleted).length || 0;

  const managers = allMembers.filter(m => (task.managerIds || []).includes(m.id));
  const nodeAssignees = allMembers.filter(m => (task.assigneeIds || []).includes(m.id));

  return (
    <div 
      className={`bg-white rounded-2xl shadow-sm border transition-all relative overflow-hidden group cursor-pointer flex flex-col p-5
        ${isActive ? 'ring-2 ring-warning border-transparent shadow-xl translate-y-[-2px]' : 'border-slate-200 hover:shadow-lg hover:translate-y-[-2px]'}
      `}
      onClick={() => onDetailClick(task)}
    >
      <div className={`absolute top-0 left-0 w-1.5 h-full 
        ${computedStatus === 'normal' || computedStatus === 'completed' ? 'bg-success' : ''}
        ${computedStatus === 'risk' ? 'bg-warning' : ''}
        ${computedStatus === 'delayed' ? 'bg-danger' : ''}
      `} />

      <div className="flex justify-between items-start mb-3">
        <div className="flex-1 min-w-0 pr-2">
          <div className="flex items-center gap-1.5 mb-1.5">
             <span className="text-[9px] px-2 py-0.5 bg-slate-900 text-warning rounded font-black uppercase truncate max-w-[120px] shadow-sm">{projectName || '常规项目'}</span>
          </div>
          <h3 className={`font-black text-base leading-tight mb-1 truncate transition-colors ${isActive ? 'text-warning' : 'text-slate-800 group-hover:text-success'}`}>{task.title}</h3>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-wider">
            交付期限: {task.dueDate} {daysLeft >= 0 ? `(剩 ${daysLeft} 天)` : `(逾期 ${Math.abs(daysLeft)} 天)`}
          </p>
        </div>

        <div className="flex flex-col items-end gap-1.5 shrink-0">
           <div className={`flex gap-1.5 transition-opacity ${isActive ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
              <button onClick={(e) => { e.stopPropagation(); onEditTask(task); }} className="p-1.5 bg-slate-50 text-slate-400 hover:text-primary rounded-lg transition-colors border border-slate-100 shadow-sm"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15.232 5.232l3.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
              <button onClick={(e) => { e.stopPropagation(); onDeleteTask(task.id); }} className="p-1.5 bg-slate-50 text-slate-400 hover:text-danger rounded-lg transition-colors border border-slate-100 shadow-sm"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
           </div>
           <span className={`px-2.5 py-0.5 text-[9px] rounded-lg font-black tracking-widest uppercase shadow-sm
            ${computedStatus === 'normal' || computedStatus === 'completed' ? 'bg-green-50 text-success border border-success/20' : ''}
            ${computedStatus === 'risk' ? 'bg-yellow-50 text-yellow-700 border border-yellow-200' : ''}
            ${computedStatus === 'delayed' ? 'bg-red-50 text-red-700 border border-red-200' : ''}
           `}>
             {statusLabel}
           </span>
        </div>
      </div>

      <p className="text-[11px] text-slate-500 line-clamp-2 italic font-medium leading-relaxed mb-4 h-8 overflow-hidden">
        "{task.outcome}"
      </p>

      {/* 管理员/指挥官 展示区 */}
      <div className="mb-3 flex items-center gap-2">
         <span className="text-[8px] font-black text-warning bg-warning/10 px-2 py-0.5 rounded border border-warning/20 uppercase shrink-0">指挥官</span>
         <div className="flex flex-wrap gap-1">
            {managers.map(m => (
              <div key={`mgr-${m.id}`} className="flex items-center gap-1 bg-warning/20 border border-warning/40 px-1.5 py-0.5 rounded shadow-sm">
                 <img src={m.avatar} className="h-3 w-3 rounded-full object-cover" />
                 <span className="text-[9px] font-black text-slate-800">{m.name}</span>
              </div>
            ))}
            {managers.length === 0 && <span className="text-[9px] text-slate-300 italic font-black uppercase">未设定主负责人</span>}
         </div>
      </div>

      <div className="mb-4 flex items-center justify-between gap-3">
         <span className="text-[9px] font-black text-slate-400 bg-slate-50 px-2 py-0.5 rounded border border-slate-100 uppercase shrink-0">
            执行项达成: {executionTasksCompleted}/{executionTasksTotal}
         </span>
         <div className="flex-1 h-2 bg-slate-100 rounded-full overflow-hidden shadow-inner">
            <div className={`h-full ${computedStatus === 'delayed' ? 'bg-danger' : 'bg-slate-400'} rounded-full transition-all duration-500`} style={{ width: executionTasksTotal > 0 ? `${(executionTasksCompleted / executionTasksTotal) * 100}%` : '0%' }}></div>
         </div>
      </div>

      <div className="mb-4 bg-slate-50/50 p-3 rounded-2xl border border-slate-100/50">
        <ProgressBar progress={task.progress} status={computedStatus} height="h-3" showLabel={false} />
        <div className="flex justify-between mt-2 items-end">
          <span className={`text-sm font-black leading-none ${isActive ? 'text-warning' : 'text-slate-900'}`}>{task.progress}%</span>
          <span className="text-[9px] text-slate-300 tracking-widest font-black uppercase">综合达成率</span>
        </div>
      </div>

      <div className="flex flex-col gap-3 pt-4 border-t border-slate-100 mt-auto">
        <div className="flex flex-wrap gap-1.5">
          <span className="text-[8px] font-black text-slate-400 uppercase w-full mb-1">执行团队:</span>
          {nodeAssignees.map(m => (
            <div key={m.id} className="flex items-center gap-1.5 bg-slate-100 border border-slate-200 px-2.5 py-1 rounded-lg transition-all hover:bg-white hover:border-warning/40 shadow-sm">
               <img src={m.avatar} className="h-4 w-4 rounded-full object-cover" />
               <span className="text-[10px] font-black text-slate-700">{m.name}</span>
            </div>
          ))}
          {nodeAssignees.length === 0 && <span className="text-[10px] text-slate-300 italic font-black uppercase tracking-widest">暂未指派执行人员</span>}
        </div>
        <button 
          onClick={(e) => { e.stopPropagation(); onUpdateClick(task); }}
          className={`w-full text-[10px] py-2.5 rounded-xl font-black uppercase tracking-widest transition-all shadow-md
            ${isActive ? 'bg-warning text-slate-900' : 'bg-slate-900 text-white hover:bg-black'}
          `}
        >
          提交日报
        </button>
      </div>
    </div>
  );
};

