async function getDbConfig() {
  if (process.env.DB_HOST && process.env.DB_USER) {
    return {
      host: process.env.DB_HOST,
      port: parseInt(process.env.DB_PORT || '3306'),
      user: process.env.DB_USER,
      password: process.env.DB_PASSWORD,
      database: process.env.DB_NAME || 'taskpulse'
    };
  }
  try {
    await fs.access(CONFIG_FILE);
    const data = await fs.readFile(CONFIG_FILE, 'utf8');
    return JSON.parse(data);
  } catch (error) {
    return null;
  }
}

async function getDbConnection() {
  const config = await getDbConfig();
  if (!config) throw new Error('DB_NOT_CONFIGURED');

  return await mysql.createConnection({
    host: config.host,
    port: config.port,
    user: config.user,
    password: config.password,
    database: config.database,
    multipleStatements: true
  });
}

const toCamel = (o) => {
  const newO = { ...o };
  if (newO.group_id) { newO.groupId = newO.group_id; delete newO.group_id; }
  if (newO.member_id) { newO.memberId = newO.member_id; delete newO.member_id; }
  if (newO.assignee_ids) {
    try { newO.assigneeIds = JSON.parse(newO.assignee_ids); } catch (e) { newO.assigneeIds = []; }
    delete newO.assignee_ids;
  }
  if (newO.manager_ids) {
    try { newO.managerIds = JSON.parse(newO.manager_ids); } catch (e) { newO.managerIds = []; }
    delete newO.manager_ids;
  }
  if (newO.start_date) { newO.startDate = newO.start_date; delete newO.start_date; }
  if (newO.due_date) { newO.dueDate = newO.due_date; delete newO.due_date; }
  if (newO.end_date) { newO.endDate = newO.end_date; delete newO.end_date; }
  if (newO.task_id) { newO.taskId = newO.task_id; delete newO.task_id; }
  if (newO.execution_task_id) { newO.executionTaskId = newO.execution_task_id; delete newO.execution_task_id; }
  if (newO.progress_snapshot) { newO.progressSnapshot = newO.progress_snapshot; delete newO.progress_snapshot; }
  if (newO.is_completed !== undefined) { newO.isCompleted = !!newO.is_completed; delete newO.is_completed; }
  if (newO.project_id) { newO.projectId = newO.project_id; delete newO.project_id; }
  if (newO.member_ids) {
    try { newO.memberIds = JSON.parse(newO.member_ids); } catch (e) { newO.memberIds = []; }
    delete newO.member_ids;
  }
  return newO;
};

const MIGRATIONS = [
  {
    version: 1,
    description: "初始化基础表结构",
    up: async (conn) => {
      const queries = [
        `CREATE TABLE IF NOT EXISTS \`groups\` (id VARCHAR(255) PRIMARY KEY, name VARCHAR(255))`,
        `CREATE TABLE IF NOT EXISTS members (id VARCHAR(255) PRIMARY KEY, name VARCHAR(255), role VARCHAR(255), avatar TEXT, group_id VARCHAR(255))`,
        `CREATE TABLE IF NOT EXISTS projects (id VARCHAR(255) PRIMARY KEY, name VARCHAR(255), description TEXT, status VARCHAR(50), start_date VARCHAR(50), end_date VARCHAR(50), member_ids TEXT)`,
        `CREATE TABLE IF NOT EXISTS tasks (id VARCHAR(255) PRIMARY KEY, title VARCHAR(255), outcome TEXT, project_id VARCHAR(255), assignee_ids TEXT, start_date VARCHAR(50), due_date VARCHAR(50), progress INT)`,
        `CREATE TABLE IF NOT EXISTS daily_logs (id VARCHAR(255) PRIMARY KEY, task_id VARCHAR(255), date VARCHAR(50), progress_snapshot INT, note TEXT)`,
        `CREATE TABLE IF NOT EXISTS milestones (id VARCHAR(255) PRIMARY KEY, task_id VARCHAR(255), title VARCHAR(255), is_completed BOOLEAN, assignee_ids TEXT)`
      ];
      for (const q of queries) await conn.query(q);
    }
  },
  {
    version: 2,
    description: "为 milestones 增加进度字段",
    up: async (conn) => {
      await conn.query(`ALTER TABLE milestones ADD COLUMN progress INT DEFAULT 0`);
    }
  },
  {
    version: 3,
    description: "日报关联具体执行任务",
    up: async (conn) => {
      await conn.query(`ALTER TABLE daily_logs ADD COLUMN execution_task_id VARCHAR(255) DEFAULT NULL`);
    }
  },
  {
    version: 4,
    description: "为 milestones 增加起止时间字段",
    up: async (conn) => {
      await conn.query(`ALTER TABLE milestones ADD COLUMN start_date VARCHAR(50), ADD COLUMN due_date VARCHAR(50)`);
    }
  },
  {
    version: 5,
    description: "为 milestones 增加交付目标愿景字段",
    up: async (conn) => {
      await conn.query(`ALTER TABLE milestones ADD COLUMN outcome TEXT`);
    }
  },
  {
    version: 6,
    description: "创建系统设置表，用于持久化 AI 配置等系统级参数",
    up: async (conn) => {
      await conn.query(`CREATE TABLE IF NOT EXISTS system_settings (setting_key VARCHAR(255) PRIMARY KEY, setting_value TEXT)`);
    }
  },
  {
    version: 7,
    description: "为 tasks 表增加 manager_ids 字段，支持作战网格多管理员权限",
    up: async (conn) => {
      await conn.query(`ALTER TABLE tasks ADD COLUMN manager_ids TEXT`);
    }
  },
  {
    version: 8,
    description: "创建用户登录表并初始化默认管理员",
    up: async (conn) => {
      await conn.query(`CREATE TABLE IF NOT EXISTS users (id VARCHAR(255) PRIMARY KEY, member_id VARCHAR(255), username VARCHAR(255) UNIQUE, password VARCHAR(255), role VARCHAR(50))`);
      // 插入默认管理员 admin / 123456
      await conn.query(`INSERT IGNORE INTO users (id, member_id, username, password, role) VALUES ('admin-uid', 'admin-mid', 'admin', '123456', 'ADMIN')`);
      await conn.query(`INSERT IGNORE INTO members (id, name, role, avatar, group_id) VALUES ('admin-mid', '系统管理员', 'Admin', 'https://picsum.photos/seed/admin/100/100', 'g1')`);
    }
  }
];

async function runMigrations(connection) {
  await connection.query(`CREATE TABLE IF NOT EXISTS _schema_version (version INT PRIMARY KEY, applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)`);
  const [rows] = await connection.query("SELECT MAX(version) as v FROM _schema_version");
  const currentVersion = rows[0].v || 0;
  let appliedCount = 0;
  for (const migration of MIGRATIONS) {
    if (migration.version > currentVersion) {
      try {
        await connection.beginTransaction();
        await migration.up(connection);
        await connection.query("INSERT INTO _schema_version (version) VALUES (?)", [migration.version]);
        await connection.commit();
        appliedCount++;
      } catch (err) {
        await connection.rollback();
        throw new Error(`Migration v${migration.version} 失败: ${err.message}`);
      }
    }
  }
  return { currentVersion: currentVersion + appliedCount, appliedCount };
}

