             <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.3em] mt-2 relative z-10">作战指挥中心 · 登录鉴权</p>
          </div>

          <div className="p-8 lg:p-10">
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">指挥官账号</label>
                <input 
                  type="text" 
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-warning outline-none font-bold text-slate-700 transition-all"
                  placeholder="Username"
                  required
                />
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">授权密钥</label>
                <input 
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-warning outline-none font-bold text-slate-700 transition-all"
                  placeholder="Password"
                  required
                />
              </div>

              {error && (
                <div className="bg-danger/10 text-danger text-[10px] font-black uppercase p-3 rounded-xl border border-danger/20 animate-shake">
                  {error}
                </div>
              )}

              <button 
                type="submit" 
                disabled={loading}
                className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl hover:bg-black transition-all flex items-center justify-center gap-2 group disabled:opacity-50"
              >
                {loading ? (
                  <div className="w-4 h-4 border-2 border-warning border-t-transparent rounded-full animate-spin"></div>
                ) : (
                  <>
                    接入作战系统
                    <svg className="w-4 h-4 text-warning group-hover:translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
                  </>
                )}
              </button>
            </form>

            <div className="mt-4 flex flex-col gap-3">
              <button 
                onClick={handleDemoMode}
                className="w-full py-3 bg-white border-2 border-slate-900 text-slate-900 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center justify-center gap-2"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                演示模式 (无需数据库)
              </button>
            </div>

            <div className="mt-8 pt-6 border-t border-slate-100 flex flex-col items-center gap-4">
              <button 
                onClick={onOpenSettings}
                className="text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-warning transition-colors flex items-center gap-2"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924-1.756-3.35 0a1.724 1.724 0 00-2.573-1.066-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /></svg>
                系统配置
              </button>
              <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest leading-relaxed text-center">
                内部战略资源系统，未经授权严禁访问<br/>
                © T&H STRATEGIC COMMAND CENTER
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Task, Member, DashboardStats, Group, Project, ExecutionTask, AiConfig, AiProvider, User, UserRole } from './types';
import { TaskCard } from './components/TaskCard';
import { UpdateModal } from './components/UpdateModal';
import { MemberManager } from './components/MemberManager';
import { ProjectManager } from './components/ProjectManager';
import { TaskFormModal } from './components/TaskFormModal';
import { TaskDetailModal } from './components/TaskDetailModal';
import { TeamStatus } from './components/TeamStatus';
import { ProjectOverview } from './components/ProjectOverview';
import { SettingsModal } from './components/SettingsModal';
import { Login } from './components/Login';
import { analyzeProjectHealth } from './services/geminiService';
import { fetchData, saveData, fetchSetting, isDemoMode } from './services/dataService';
import { marked } from 'marked';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [members, setMembers] = useState<Member[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [projects, setProjects] = useState<Project[]>([]);
  const [aiConfig, setAiConfig] = useState<AiConfig>({ provider: AiProvider.GEMINI });
  const [isLoading, setIsLoading] = useState(true);
  const [activeView, setActiveView] = useState<'tasks' | 'overview'>('overview');
  const [saveStatus, setSaveStatus] = useState<'saved' | 'saving' | 'error' | 'local'>('saved');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const initialLoadComplete = useRef(false);

  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);
  const [filterProjectId, setFilterProjectId] = useState<string>('all');
  const [filterGroupId, setFilterGroupId] = useState<string>('all');
  const [filterMemberId, setFilterMemberId] = useState<string>('all');

  useEffect(() => {
    const savedUser = localStorage.getItem('th_user');
    if (savedUser) {
      try {
        const parsed = JSON.parse(savedUser);
        setCurrentUser(parsed);
      } catch (e) {
        localStorage.removeItem('th_user');
      }
    }
    // 首次加载，如果是后端模式，可能需要配置 DB
    checkInitStatus();
  }, []);

  const checkInitStatus = async () => {
    try {
      if (!isDemoMode()) {
        await fetchData(null);
      }
      setIsLoading(false);
    } catch (err: any) {
      if (err.message === 'DB_NOT_CONFIGURED') {
        // 如果未配置 DB 且不是演示模式，可能需要弹窗提示，或者在登录页处理
      }
      setIsLoading(false);
    }
  };

  const loadData = async () => {
    if (!currentUser) return;
    setIsLoading(true);
    try {
      const data = await fetchData(currentUser);
      setTasks(data.tasks);
      setMembers(data.members);
      setGroups(data.groups);
      setProjects(data.projects || []);

      const aiSettings = await fetchSetting('ai_config');
      if (aiSettings) {
        setAiConfig(aiSettings);
      }

      initialLoadComplete.current = true;
    } catch (err: any) {
      if (err.message === 'DB_NOT_CONFIGURED') setIsSettingsOpen(true);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (currentUser) {
      loadData();
    }
  }, [currentUser]);

  useEffect(() => {
    if (!initialLoadComplete.current || !currentUser) return;
    setSaveStatus('saving');
    const timer = setTimeout(() => {
      saveData({ tasks, members, groups, projects })
        .then((result) => setSaveStatus(result.mode === 'local' ? 'local' : 'saved'))
        .catch(() => setSaveStatus('error'));
    }, 1000); 
    return () => clearTimeout(timer);
  }, [tasks, members, groups, projects, currentUser]);

  const [selectedSubTaskForUpdate, setSelectedSubTaskForUpdate] = useState<{task: Task, subTask: ExecutionTask} | null>(null);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [isUpdateModalOpen, setIsUpdateModalOpen] = useState(false);
  const [isMemberManagerOpen, setIsMemberManagerOpen] = useState(false);
  const [isProjectManagerOpen, setIsProjectManagerOpen] = useState(false);
  const [isTaskFormOpen, setIsTaskFormOpen] = useState(false);
  const [isTaskDetailOpen, setIsTaskDetailOpen] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);

  const filteredMembers = useMemo(() => {
    if (filterProjectId !== 'all') {
      const project = projects.find(p => p.id === filterProjectId);
      if (project && project.memberIds && project.memberIds.length > 0) {
        let membersInProject = members.filter(m => project.memberIds.includes(m.id));
        if (filterGroupId !== 'all') membersInProject = membersInProject.filter(m => m.groupId === filterGroupId);
        return membersInProject;
      }
    }
    if (filterGroupId === 'all') return members;
    return members.filter(m => m.groupId === filterGroupId);
  }, [members, projects, filterProjectId, filterGroupId]);

  const filteredNodes = useMemo(() => {
    let result = tasks;

    // 如果是普通成员，只看自己相关的（除非是演示模式或有特殊逻辑）
    // 此处可增加逻辑，但目前先保持展示逻辑

    if (filterProjectId !== 'all') result = result.filter(t => t.projectId === filterProjectId);
    if (filterMemberId !== 'all') {
      result = result.filter(t => (t.assigneeIds || []).includes(filterMemberId) || (t.executionTasks || []).some(et => (et.assigneeIds || []).includes(filterMemberId)));
    } else if (filterGroupId !== 'all') {
      const memberIdsInGroup = members.filter(m => m.groupId === filterGroupId).map(m => m.id);
      result = result.filter(t => (t.assigneeIds || []).some(aid => memberIdsInGroup.includes(aid)) || (t.executionTasks || []).some(et => (et.assigneeIds || []).some(aid => memberIdsInGroup.includes(aid))));
    }
    return result;
  }, [tasks, filterProjectId, filterMemberId, filterGroupId, members]);

  const rawSelectedNode = useMemo(() => tasks.find(t => t.id === selectedNodeId) || null, [tasks, selectedNodeId]);

  const stats: DashboardStats = useMemo(() => {
    let completed = 0, delayed = 0, atRisk = 0;
    const today = new Date();
    filteredNodes.forEach(t => {
      if (t.progress === 100) completed++;
      else {
        const daysLeft = Math.ceil((new Date(t.dueDate).getTime() - today.getTime()) / (1000 * 3600 * 24));
        if (daysLeft < 0) delayed++;
        else if (daysLeft <= 3 && t.progress < 80) atRisk++;
      }
    });
    return { total: filteredNodes.length, completed, delayed, atRisk };
  }, [filteredNodes]);

  const handleSaveSubTaskProgress = (taskId: string, executionTaskId: string, newProgress: number, note: string) => {
    setTasks(prev => prev.map(t => {
      if (t.id === taskId) {
        const updatedETs = t.executionTasks.map(et => et.id === executionTaskId ? { ...et, progress: newProgress, isCompleted: newProgress === 100 } : et);
        const avgProgress = updatedETs.length > 0 ? Math.round(updatedETs.reduce((acc, curr) => acc + curr.progress, 0) / updatedETs.length) : t.progress;
        return { ...t, executionTasks: updatedETs, progress: avgProgress, logs: [...(t.logs || []), { id: Date.now().toString(), date: new Date().toISOString(), progressSnapshot: newProgress, note, executionTaskId }] };
      }
      return t;
    }));
  };

  const handleAnalyze = async () => {
    setIsAnalyzing(true); setAiAnalysis(null);
    try {
      const result = await analyzeProjectHealth(filteredNodes, members, aiConfig);
      setAiAnalysis(result);
    } catch (error) {
      console.error("Analysis error:", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleLoginSuccess = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('th_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    if (window.confirm('确定要退出作战系统吗？')) {
      setCurrentUser(null);
      localStorage.removeItem('th_user');
      setTasks([]);
      setProjects([]);
      initialLoadComplete.current = false;
    }
  };

  // Markdown 渲染组件
  const MarkdownBody = ({ content }: { content: string }) => {
    const html = marked(content) as string;
    return (
      <div 
        className="ai-report-content text-slate-300 text-sm leading-relaxed whitespace-normal font-medium border-l-2 border-warning/30 pl-6 py-2"
        dangerouslySetInnerHTML={{ __html: html }}
      />
    );
  };

  if (!currentUser) {
    return <Login onLoginSuccess={handleLoginSuccess} onOpenSettings={() => setIsSettingsOpen(true)} />;
  }

  if (isLoading) return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50">
      <div className="flex flex-col items-center gap-4">
        <div className="w-8 h-8 border-4 border-warning border-t-transparent rounded-full animate-spin"></div>
        <p className="text-slate-500 font-black text-xs uppercase tracking-widest text-warning">同步权限并加载视界...</p>
      </div>
    </div>
  );

  const loggedInMember = members.find(m => m.id === currentUser.memberId);

  return (
    <div className="min-h-screen bg-[#f8fafc] text-slate-900 font-sans selection:bg-warning/30">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40 shadow-sm transition-all">
        <div className="max-w-[1600px] mx-auto px-4 lg:px-8">
          <div className="h-14 lg:h-16 flex items-center justify-between">
            <div className="flex items-center gap-3 shrink-0 cursor-pointer" onClick={() => setActiveView('overview')}>
              <div className="w-8 h-8 lg:w-9 lg:h-9 bg-slate-900 rounded-xl flex items-center justify-center text-warning font-black text-lg lg:text-xl shadow-lg">T</div>
              <div className="flex flex-col">
                <h1 className="text-sm lg:text-lg font-black tracking-tighter leading-none">
                  <span className="text-warning">T&H</span> <span className="text-success hidden xs:inline">INTERNATIONAL</span>
                </h1>
                <div className="flex items-center gap-1 mt-0.5">
                   <div className={`w-1.5 h-1.5 rounded-full ${saveStatus === 'saving' ? 'bg-warning animate-pulse' : 'bg-success'}`}></div>
                   <span className="text-[8px] lg:text-[9px] font-black uppercase text-slate-400 tracking-wider">
                     系统联通中 · {isDemoMode() ? '演示视窗' : (currentUser.role === UserRole.ADMIN ? '最高权限' : '成员视界')}
                   </span>
                </div>
              </div>
            </div>

            <nav className="hidden md:flex bg-slate-100 p-1 rounded-xl gap-1 mx-4">
              <button onClick={() => setActiveView('overview')} className={`px-5 py-1.5 rounded-lg text-xs font-black uppercase transition-all ${activeView === 'overview' ? 'bg-white text-slate-900 shadow-sm ring-1 ring-slate-200' : 'text-slate-400 hover:text-slate-600'}`}>战略概览</button>
              <button onClick={() => setActiveView('tasks')} className={`px-5 py-1.5 rounded-lg text-xs font-black uppercase transition-all ${activeView === 'tasks' ? 'bg-white text-slate-900 shadow-sm ring-1 ring-slate-200' : 'text-slate-400 hover:text-slate-600'}`}>作战指挥</button>
            </nav>

            <div className="flex items-center gap-2">
              <div className="hidden sm:flex items-center gap-2 mr-2 px-3 py-1.5 bg-slate-50 rounded-xl border border-slate-100">
                 <img src={loggedInMember?.avatar || `https://ui-avatars.com/api/?name=${currentUser.username}`} className="w-6 h-6 rounded-full border border-warning" />
                 <div className="flex flex-col">
                    <span className="text-[10px] font-black text-slate-800 leading-none">{loggedInMember?.name || currentUser.username}</span>
                    <span className="text-[8px] font-black text-slate-400 uppercase">{loggedInMember?.role || '指挥官'}</span>
                 </div>
              </div>

              {currentUser.role === UserRole.ADMIN && (
                <>
                  <button onClick={() => setIsProjectManagerOpen(true)} className="hidden sm:flex items-center gap-2 px-3 py-1.5 bg-warning/10 text-warning rounded-lg hover:bg-warning/20 transition-all font-black text-[10px] uppercase border border-warning/20">立项管理</button>
                  <button onClick={() => setIsMemberManagerOpen(true)} className="p-2 bg-slate-50 text-slate-400 hover:bg-success hover:text-white rounded-lg transition-all"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg></button>
                </>
              )}

              <button onClick={() => setIsSettingsOpen(true)} className="p-2 bg-slate-50 text-slate-400 hover:text-slate-800 rounded-lg transition-all"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924-1.756-3.35 0a1.724 1.724 0 00-2.573-1.066-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /></svg></button>
              <button onClick={handleLogout} className="p-2 bg-slate-50 text-danger hover:bg-danger/10 rounded-lg transition-all" title="退出系统"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg></button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-[1600px] mx-auto px-4 lg:px-8 py-4 lg:py-6">
        {activeView === 'overview' ? (
          <ProjectOverview 
            projects={projects} tasks={tasks} allMembers={members}
            onProjectClick={(id) => { setFilterProjectId(id); setActiveView('tasks'); }} 
            onNavigateToTask={(pid, tid) => { setFilterProjectId(pid); setSelectedNodeId(tid); setActiveView('tasks'); }}
            onAddNewProject={() => setIsProjectManagerOpen(true)}
          />
        ) : (
          <div className="animate-[fadeIn_0.4s_ease-out]">
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-2 lg:gap-4 mb-6">
              {[
                { label: '核心节点', val: stats.total, color: 'text-slate-800' },
                { label: '节点达成', val: stats.completed, color: 'text-success', border: 'border-b-success' },
                { label: '风险警戒', val: stats.atRisk, color: 'text-warning', border: 'border-b-warning' },
                { label: '逾期攻坚', val: stats.delayed, color: 'text-danger', border: 'border-b-danger' }
              ].map((s, i) => (
                <div key={i} className={`bg-white p-3 lg:p-4 rounded-xl shadow-sm border border-slate-100 ${s.border ? `border-b-4 ${s.border}` : ''}`}>
                  <span className={`text-xl lg:text-3xl font-black tracking-tighter ${s.color}`}>{s.val}</span>
                  <div className="text-[9px] lg:text-[10px] text-slate-400 mt-1 uppercase font-black tracking-widest border-t border-slate-50 pt-1">{s.label}</div>
                </div>
              ))}
            </div>

            <TeamStatus members={filteredMembers} tasks={tasks} />

            <div className="mt-6 flex flex-col gap-3 lg:gap-5 bg-white p-4 lg:p-6 rounded-[2rem] shadow-sm border border-slate-100">
               <div className="flex items-center gap-2 overflow-x-auto pb-1 scrollbar-hide">
                <div className="shrink-0 text-[10px] font-black text-slate-300 uppercase tracking-widest px-2">立项指挥</div>
                <button onClick={() => { setFilterProjectId('all'); setSelectedNodeId(null); }} className={`shrink-0 px-4 py-1.5 rounded-xl text-[10px] font-black uppercase transition-all ${filterProjectId === 'all' ? 'bg-success text-white ring-2 ring-success/30 shadow-lg' : 'bg-slate-50 text-slate-400 border border-slate-200 hover:text-slate-600'}`}>视界全盘</button>
                {projects.map(p => (
                  <button key={p.id} onClick={() => { setFilterProjectId(p.id); setSelectedNodeId(null); }} className={`shrink-0 px-4 py-1.5 rounded-xl text-[10px] font-black uppercase transition-all whitespace-nowrap flex items-center gap-2 ${filterProjectId === p.id ? 'bg-slate-900 text-white ring-2 ring-warning shadow-lg' : 'bg-slate-50 text-slate-400 border border-slate-200 hover:text-slate-600'}`}>
                    {p.name}
                  </button>
                ))}
              </div>

              <div className="flex flex-col xl:flex-row gap-4">
                <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-3">
                   <div className="flex items-center gap-2 overflow-x-auto scrollbar-hide bg-slate-50/80 p-2 rounded-xl border border-slate-100">
                      <span className="shrink-0 text-[9px] font-black text-slate-400 uppercase w-10 text-center">组织</span>
                      <button onClick={() => { setFilterGroupId('all'); setFilterMemberId('all'); }} className={`shrink-0 px-3 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${filterGroupId === 'all' ? 'bg-slate-800 text-white shadow-md' : 'text-slate-400 hover:bg-white hover:text-slate-600'}`}>全公司</button>
                      {groups.map(g => (
                        <button key={g.id} onClick={() => { setFilterGroupId(g.id); setFilterMemberId('all'); }} className={`shrink-0 px-3 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${filterGroupId === g.id ? 'bg-slate-800 text-white shadow-md ring-1 ring-slate-400' : 'text-slate-400 hover:bg-white hover:text-slate-600'}`}>{g.name}</button>
                      ))}
                   </div>
                   <div className="flex items-center gap-2 overflow-x-auto scrollbar-hide bg-slate-50/80 p-2 rounded-xl border border-slate-100">
                      <span className="shrink-0 text-[9px] font-black text-slate-400 uppercase w-10 text-center">协作</span>
                      <button onClick={() => setFilterMemberId('all')} className={`shrink-0 px-3 py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${filterMemberId === 'all' ? 'bg-slate-800 text-white shadow-md' : 'text-slate-400 hover:bg-white hover:text-slate-600'}`}>全员</button>
                      {filteredMembers.map(m => (
