        onToggleExecutionTask={(taskId, etId) => { setTasks(prev => prev.map(t => t.id === taskId ? { ...t, executionTasks: t.executionTasks.map(et => et.id === etId ? { ...et, isCompleted: !et.isCompleted, progress: !et.isCompleted ? 100 : 0 } : et) } : t)); }} 
        onDeleteExecutionTask={(taskId, etId) => { setTasks(prev => prev.map(t => t.id === taskId ? { ...t, executionTasks: t.executionTasks.filter(et => et.id !== etId) } : t)); }} 
      />
      <UpdateModal subTask={selectedSubTaskForUpdate?.subTask || null} parentTask={selectedSubTaskForUpdate?.task || null} isOpen={isUpdateModalOpen} onClose={() => setIsUpdateModalOpen(false)} onSave={handleSaveSubTaskProgress} />
      <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} onConfigSaved={() => loadData()} />
    </div>
  );
};

