    await connection.query('DELETE FROM daily_logs');
    await connection.query('DELETE FROM milestones');
    await connection.query('DELETE FROM tasks');
    await connection.query('DELETE FROM members');
    await connection.query('DELETE FROM \`groups\`');
    await connection.query('DELETE FROM projects');

    if (groups?.length) await connection.query('INSERT INTO \`groups\` (id, name) VALUES ?', [groups.map(g => [g.id, g.name])]);
    if (members?.length) await connection.query('INSERT INTO members (id, name, role, avatar, group_id) VALUES ?', [members.map(m => [m.id, m.name, m.role, m.avatar, m.groupId])]);
    if (projects?.length) await connection.query('INSERT INTO projects (id, name, description, status, start_date, end_date, member_ids) VALUES ?', 
      [projects.map(p => [p.id, p.name, p.description, p.status, p.startDate, p.endDate, JSON.stringify(p.memberIds || [])])]);

    if (tasks?.length) {
      await connection.query('INSERT INTO tasks (id, title, outcome, project_id, assignee_ids, manager_ids, start_date, due_date, progress) VALUES ?', 
        [tasks.map(t => [t.id, t.title, t.outcome, t.projectId || 'default_project', JSON.stringify(t.assigneeIds || []), JSON.stringify(t.managerIds || []), t.startDate, t.dueDate, t.progress])]);

      const logValues = [];
      const msValues = [];
      tasks.forEach(t => {
        t.logs?.forEach(l => logValues.push([l.id, t.id, l.date, l.progressSnapshot, l.note, l.executionTaskId || null]));
        t.executionTasks?.forEach(m => msValues.push([m.id, t.id, m.title, m.isCompleted, JSON.stringify(m.assigneeIds || []), m.progress || 0, m.startDate, m.dueDate, m.outcome || '']));
      });
      if (logValues.length) await connection.query('INSERT INTO daily_logs (id, task_id, date, progress_snapshot, note, execution_task_id) VALUES ?', [logValues]);
      if (msValues.length) await connection.query('INSERT INTO milestones (id, task_id, title, is_completed, assignee_ids, progress, start_date, due_date, outcome) VALUES ?', [msValues]);
    }

    await connection.commit();
    res.json({ success: true });
  } catch (error) { if (connection) await connection.rollback(); res.status(500).json({ error: error.message }); } finally { if (connection) await connection.end(); }
});

app.get('*', (req, res) => res.sendFile(path.join(__dirname, 'dist', 'index.html')));
app.listen(PORT, () => console.log(`后端服务已启动：端口 ${PORT}`));

import { Task, Member, Group, Project, ProjectStatus, User } from '../types';
import { INITIAL_TASKS, MOCK_MEMBERS, MOCK_GROUPS } from '../constants';

const API_BASE = '/api';
const STORAGE_KEY = 'taskpulse_data_cache';
const DEMO_MODE_KEY = 'th_demo_mode';

export interface AppData {
  tasks: Task[];
  members: Member[];
  groups: Group[];
  projects: Project[];
}

export interface SaveResult {
  success: boolean;
  mode: 'server' | 'local';
}

const DEFAULT_PROJECTS: Project[] = [
  {
    id: 'default_project',
    name: '常规项目',
    description: '默认任务归属',
    status: ProjectStatus.ACTIVE,
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    memberIds: []
  }
];

const getDefaultData = (): AppData => ({
  tasks: INITIAL_TASKS,
  members: MOCK_MEMBERS,
  groups: MOCK_GROUPS,
  projects: DEFAULT_PROJECTS
});

export const isDemoMode = () => localStorage.getItem(DEMO_MODE_KEY) === 'true';
export const setDemoMode = (val: boolean) => localStorage.setItem(DEMO_MODE_KEY, val.toString());

export const login = async (username: string, password: string): Promise<User> => {
  if (isDemoMode()) {
    return { id: 'demo-user', username: '体验官', role: 'ADMIN' as any };
  }
  const res = await fetch(`${API_BASE}/login`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ username, password })
  });
  if (!res.ok) {
    const err = await res.json();
    throw new Error(err.error || '登录失败');
  }
  const data = await res.json();
  return data.user;
};

export const getConfig = async () => {
  try {
    const res = await fetch(`${API_BASE}/config`);
    if (!res.ok) throw new Error('Failed to fetch config');
    return await res.json();
  } catch (error) {
    return {};
  }
};

export const saveConfig = async (config: any) => {
  const res = await fetch(`${API_BASE}/config`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(config)
  });
  if (!res.ok) throw new Error('Failed to save config');
  return await res.json();
};

export const fetchSetting = async (key: string) => {
  if (isDemoMode()) {
    const localVal = localStorage.getItem(`th_setting_${key}`);
    return localVal ? JSON.parse(localVal) : null;
  }
  try {
    const res = await fetch(`${API_BASE}/settings/${key}`);
    if (!res.ok) return null;
    const data = await res.json();
    return data.value;
  } catch (error) {
    return null;
  }
};

export const saveSetting = async (key: string, value: any) => {
  if (isDemoMode()) {
    localStorage.setItem(`th_setting_${key}`, JSON.stringify(value));
    return true;
  }
  try {
    const res = await fetch(`${API_BASE}/settings/${key}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(value)
    });
    return res.ok;
  } catch (error) {
    return false;
  }
};

export const initDb = async () => {
  const res = await fetch(`${API_BASE}/init`, { method: 'POST' });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error || 'Init failed');
  return data;
};

export const checkDbConnection = async (): Promise<boolean> => {
  try {
    const res = await fetch(`${API_BASE}/data`);
    return res.ok;
  } catch {
    return false;
  }
};

export const fetchData = async (user: User | null): Promise<AppData> => {
  if (isDemoMode()) {
    const cached = localStorage.getItem(STORAGE_KEY);
    return cached ? JSON.parse(cached) : getDefaultData();
  }

  try {
    const response = await fetch(`${API_BASE}/data`);
    if (response.status === 401 || response.status === 503) {
      const err = await response.json().catch(() => ({}));
      if (err.error?.includes('DB_NOT_CONFIGURED')) throw new Error('DB_NOT_CONFIGURED');
    }
    if (!response.ok) {
       const text = await response.text();
       if (text.includes('DB_NOT_CONFIGURED')) throw new Error('DB_NOT_CONFIGURED');
       throw new Error('Server response not ok');
    }
    const data = await response.json();
    if (!data.projects?.length) data.projects = DEFAULT_PROJECTS;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    return data;
  } catch (error: any) {
    if (error.message === 'DB_NOT_CONFIGURED') throw error;
    const cached = localStorage.getItem(STORAGE_KEY);
    if (cached) {
      try { return JSON.parse(cached); } catch (e) {}
    }
    return getDefaultData();
  }
};

export const saveData = async (data: AppData): Promise<SaveResult> => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
  if (isDemoMode()) return { success: true, mode: 'local' };

  try {
    const response = await fetch(`${API_BASE}/data`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });
    return response.ok ? { success: true, mode: 'server' } : { success: false, mode: 'local' };
  } catch (error) {
    return { success: true, mode: 'local' };
  }
};

