import { Task, Member, Group, Project, ProjectStatus, User } from '../types';
import { INITIAL_TASKS, MOCK_MEMBERS, MOCK_GROUPS } from '../constants';

const API_BASE = '/api';
const STORAGE_KEY = 'taskpulse_data_cache';
const DEMO_MODE_KEY = 'th_demo_mode';

export interface AppData {
  tasks: Task[];
  members: Member[];
  groups: Group[];
  projects: Project[];
}

export interface SaveResult {
  success: boolean;
  mode: 'server' | 'local';
}

const DEFAULT_PROJECTS: Project[] = [
  {
    id: 'default_project',
    name: '常规项目',
    description: '默认任务归属',
    status: ProjectStatus.ACTIVE,
    startDate: new Date().toISOString().split('T')[0],
    endDate: '',
    memberIds: []
  }
];

const getDefaultData = (): AppData => ({
  tasks: INITIAL_TASKS,
  members: MOCK_MEMBERS,
  groups: MOCK_GROUPS,
  projects: DEFAULT_PROJECTS
});

export const isDemoMode = () => localStorage.getItem(DEMO_MODE_KEY) === 'true';
export const setDemoMode = (val: boolean) => localStorage.setItem(DEMO_MODE_KEY, val.toString());

export const login = async (username: string, password: string): Promise<User> => {
  if (isDemoMode()) {
    return { id: 'demo-user', username: '体验官', role: 'ADMIN' as any };
  }
  const res = await fetch(`${API_BASE}/login`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ username, password })
  });
  if (!res.ok) {
    const err = await res.json();
    throw new Error(err.error || '登录失败');
  }
  const data = await res.json();
  return data.user;
};

export const changePassword = async (userId: string, newPassword: string): Promise<boolean> => {
  if (isDemoMode()) return true;
  const res = await fetch(`${API_BASE}/change-password`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ userId, newPassword })
  });
  return res.ok;
};

export const getConfig = async () => {
  try {
    const res = await fetch(`${API_BASE}/config`);
    if (!res.ok) throw new Error('Failed to fetch config');
    return await res.json();
  } catch (error) {
    return {};
  }
};

export const saveConfig = async (config: any) => {
  const res = await fetch(`${API_BASE}/config`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(config)
  });
  if (!res.ok) throw new Error('Failed to save config');
  return await res.json();
};

export const fetchSetting = async (key: string) => {
  if (isDemoMode()) {
    const localVal = localStorage.getItem(`th_setting_${key}`);
    return localVal ? JSON.parse(localVal) : null;
  }
  try {
    const res = await fetch(`${API_BASE}/settings/${key}`);
    if (!res.ok) return null;
    const data = await res.json();
    return data.value;
  } catch (error) {
    return null;
  }
};

export const saveSetting = async (key: string, value: any) => {
  if (isDemoMode()) {
    localStorage.setItem(`th_setting_${key}`, JSON.stringify(value));
    return true;
  }
  try {
    const res = await fetch(`${API_BASE}/settings/${key}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(value)
    });
    return res.ok;
  } catch (error) {
    return false;
  }
};

export const initDb = async () => {
  const res = await fetch(`${API_BASE}/init`, { method: 'POST' });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error || 'Init failed');
  return data;
};

export const checkDbConnection = async (): Promise<boolean> => {
  try {
    const res = await fetch(`${API_BASE}/data`);
    return res.ok;
  } catch {
    return false;
  }
};

export const fetchData = async (user: User | null): Promise<AppData> => {
  if (isDemoMode()) {
    const cached = localStorage.getItem(STORAGE_KEY);
    return cached ? JSON.parse(cached) : getDefaultData();
  }

  try {
    const response = await fetch(`${API_BASE}/data`);
    if (response.status === 401 || response.status === 503) {
      const err = await response.json().catch(() => ({}));
      if (err.error?.includes('DB_NOT_CONFIGURED')) throw new Error('DB_NOT_CONFIGURED');
    }
    if (!response.ok) {
       const text = await response.text();
       if (text.includes('DB_NOT_CONFIGURED')) throw new Error('DB_NOT_CONFIGURED');
       throw new Error('Server response not ok');
    }
    const data = await response.json();
    if (!data.projects?.length) data.projects = DEFAULT_PROJECTS;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    return data;
  } catch (error: any) {
    if (error.message === 'DB_NOT_CONFIGURED') throw error;
    const cached = localStorage.getItem(STORAGE_KEY);
    if (cached) {
      try { return JSON.parse(cached); } catch (e) {}
    }
    return getDefaultData();
  }
};

export const saveData = async (data: AppData): Promise<SaveResult> => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
  if (isDemoMode()) return { success: true, mode: 'local' };

  try {
    const response = await fetch(`${API_BASE}/data`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });
    return response.ok ? { success: true, mode: 'server' } : { success: false, mode: 'local' };
  } catch (error) {
    return { success: true, mode: 'local' };
  }
};

import React, { useState } from 'react';
import { User } from '../types';
import { changePassword } from '../services/dataService';

interface PasswordChangeModalProps {
  user: User;
  isOpen: boolean;
  onClose: () => void;
}

export const PasswordChangeModal: React.FC<PasswordChangeModalProps> = ({ user, isOpen, onClose }) => {
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  if (!isOpen) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newPassword.length < 6) {
      setError('密钥长度至少为 6 位');
      return;
    }
    if (newPassword !== confirmPassword) {
      setError('两次输入的密钥不一致');
      return;
    }

    setLoading(true);
    setError('');
    try {
      const success = await changePassword(user.id, newPassword);
      if (success) {
        alert('密钥修改成功，请牢记您的新密钥');
        onClose();
      } else {
        setError('服务器响应异常，请稍后重试');
      }
    } catch (err: any) {
      setError(err.message || '修改失败');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 backdrop-blur-md">
      <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-md p-8 m-4 animate-[fadeIn_0.2s_ease-out]">
        <div className="text-center mb-8">
           <div className="w-16 h-16 bg-slate-900 text-warning rounded-2xl flex items-center justify-center mx-auto mb-4 text-2xl font-black shadow-lg">P</div>
           <h2 className="text-xl font-black text-slate-800 tracking-tight">修改指挥官密钥</h2>
           <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mt-1">账号: {user.username}</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">新密钥 (New Password)</label>
            <input 
              type="password" 
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
              className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-warning outline-none font-bold text-slate-700"
              placeholder="请输入新密钥"
              required
            />
          </div>

          <div>
            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">确认新密钥 (Confirm Password)</label>
            <input 
              type="password" 
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-warning outline-none font-bold text-slate-700"
              placeholder="请再次确认密钥"
              required
            />
          </div>

          {error && (
            <div className="bg-danger/10 text-danger text-[10px] font-black uppercase p-3 rounded-xl border border-danger/20">
              {error}
            </div>
          )}

          <div className="flex gap-3">
             <button type="button" onClick={onClose} className="flex-1 py-4 bg-slate-50 text-slate-400 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:text-slate-800 transition-all">取消</button>
             <button 
               type="submit" 
               disabled={loading}
               className="flex-1 py-4 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:bg-black transition-all flex items-center justify-center gap-2"
             >
               {loading ? <div className="w-3 h-3 border-2 border-warning border-t-transparent rounded-full animate-spin"></div> : '确认修改'}
             </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Member, Group } from '../types';

interface MemberManagerProps {
  isOpen: boolean;
  onClose: () => void;
  members: Member[];
  groups: Group[];
  onAddMember: (member: Member) => void;
  onUpdateMember: (member: Member) => void;
  onDeleteMember: (id: string) => void;
  onAddGroup: (group: Group) => void;
  onUpdateGroup: (group: Group) => void;
  onDeleteGroup: (id: string) => void;
}

export const MemberManager: React.FC<MemberManagerProps> = ({
  isOpen,
  onClose,
  members,
  groups,
  onAddMember,
  onUpdateMember,
  onDeleteMember,
  onAddGroup,
  onUpdateGroup,
  onDeleteGroup,
}) => {
  const [activeTab, setActiveTab] = useState<'members' | 'groups'>('members');

  // --- Member State ---
  const [editingMemberId, setEditingMemberId] = useState<string | null>(null);
  const [memberFormData, setMemberFormData] = useState<Partial<Member>>({});
  const [isAddingMember, setIsAddingMember] = useState(false);

  // --- Group State ---
  const [editingGroupId, setEditingGroupId] = useState<string | null>(null);
  const [groupFormData, setGroupFormData] = useState<Partial<Group>>({});
  const [isAddingGroup, setIsAddingGroup] = useState(false);

  if (!isOpen) return null;

  // --- Member Functions ---
  const resetMemberForm = () => {
    setEditingMemberId(null);
    setIsAddingMember(false);
    setMemberFormData({});
  };

  const startEditMember = (member: Member) => {
    setEditingMemberId(member.id);
    setMemberFormData(member);
    setIsAddingMember(false);
  };

  const startAddMember = () => {
    setIsAddingMember(true);
    setEditingMemberId(null);
    setMemberFormData({
      id: Date.now().toString(),
      avatar: `https://picsum.photos/seed/${Date.now()}/100/100`,
      groupId: groups.length > 0 ? groups[0].id : '',
      password: '666666' // 默认初始密码
    });
  };

  const handleMemberSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!memberFormData.name || !memberFormData.role || !memberFormData.groupId) {
       if (!memberFormData.groupId && groups.length > 0) {
          alert("请选择一个所属组");
          return;
       } else if (groups.length === 0) {
          alert("请先创建分组");
          return;
       }
       return;
    }

    const memberData = memberFormData as Member;

    if (isAddingMember) {
      onAddMember(memberData);
    } else {
      onUpdateMember(memberData);
    }
    resetMemberForm();
  };

  // --- Group Functions ---
  const resetGroupForm = () => {
    setEditingGroupId(null);
    setIsAddingGroup(false);
    setGroupFormData({});
  };

  const startEditGroup = (group: Group) => {
    setEditingGroupId(group.id);
    setGroupFormData(group);
    setIsAddingGroup(false);
  };

  const startAddGroup = () => {
    setIsAddingGroup(true);
    setEditingGroupId(null);
    setGroupFormData({
      id: `g-${Date.now()}`,
      name: ''
    });
  };

  const handleGroupSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!groupFormData.name) return;

    const groupData = groupFormData as Group;
    if (isAddingGroup) {
      onAddGroup(groupData);
    } else {
      onUpdateGroup(groupData);
    }
    resetGroupForm();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
      <div className="bg-white rounded-[2.5rem] shadow-xl w-full max-w-2xl p-0 m-4 max-h-[90vh] overflow-hidden flex flex-col border border-slate-200">

        {/* Header with Tabs */}
        <div className="bg-slate-50 border-b border-slate-200 px-8 pt-8 pb-0 flex flex-col">
          <div className="flex justify-between items-center mb-6">
            <div>
              <h2 className="text-2xl font-black text-slate-800 tracking-tight">团队架构中心</h2>
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mt-1">管理作战编制与登录权限</p>
            </div>
            <button onClick={onClose} className="p-2 bg-white rounded-full shadow-sm text-slate-400 hover:text-slate-800 transition-all">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>
          <div className="flex space-x-8">
            <button 
              onClick={() => setActiveTab('members')}
              className={`pb-3 text-xs font-black uppercase tracking-widest border-b-4 transition-all ${
                activeTab === 'members' 
                  ? 'border-warning text-slate-800' 
                  : 'border-transparent text-slate-400 hover:text-slate-600'
              }`}
            >
              全员名册
            </button>
            <button 
              onClick={() => setActiveTab('groups')}
              className={`pb-3 text-xs font-black uppercase tracking-widest border-b-4 transition-all ${
                activeTab === 'groups' 
                  ? 'border-warning text-slate-800' 
                  : 'border-transparent text-slate-400 hover:text-slate-600'
              }`}
            >
              编制分组
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-8 scrollbar-hide">

          {/* ================= MEMBERS TAB ================= */}
          {activeTab === 'members' && (
            <>
              {!isAddingMember && !editingMemberId && (
                <div>
